import java.util.Scanner;

public class SafeBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];
        int length = Math.min(userInput.length(), buffer.length); // Limit the length to prevent buffer overflow

        userInput.getChars(0, length, buffer, 0);

        for (int i = 0; i < length; i++) { // Use < instead of <= to ensure index stays within bounds
            System.out.print(buffer[i]);
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
